import React, { useState } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { 
  LayoutDashboard, 
  BookOpen, 
  Wallet, 
  Users, 
  GraduationCap, 
  Menu, 
  X,
  Bell,
  Search,
  MessageSquare
} from 'lucide-react';

interface LayoutProps {
  children: React.ReactNode;
}

const Layout: React.FC<LayoutProps> = ({ children }) => {
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const location = useLocation();

  const navItems = [
    { name: 'Dashboard', icon: LayoutDashboard, path: '/' },
    { name: 'Academics', icon: GraduationCap, path: '/academics' },
    { name: 'Admissions', icon: BookOpen, path: '/admissions' },
    { name: 'Advising', icon: Users, path: '/advising' },
    { name: 'Finances', icon: Wallet, path: '/finances' },
  ];

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col md:flex-row">
      {/* Desktop Sidebar */}
      <aside className="hidden md:flex flex-col w-64 bg-indigo-900 text-white fixed h-full shadow-xl">
        <div className="p-6 flex items-center space-x-2">
          <div className="w-8 h-8 bg-indigo-500 rounded-lg flex items-center justify-center font-bold text-white">EP</div>
          <span className="text-xl font-bold tracking-tight">EduPulse</span>
        </div>
        <nav className="flex-1 mt-4 px-3 space-y-1">
          {navItems.map((item) => (
            <Link
              key={item.name}
              to={item.path}
              className={`flex items-center space-x-3 p-3 rounded-lg transition-colors ${
                location.pathname === item.path ? 'bg-indigo-800 text-white shadow-md' : 'text-indigo-200 hover:bg-indigo-800/50 hover:text-white'
              }`}
            >
              <item.icon size={20} />
              <span className="font-medium">{item.name}</span>
            </Link>
          ))}
        </nav>
        <div className="p-4 bg-indigo-950 border-t border-indigo-800">
          <div className="flex items-center space-x-3">
            <img src="https://picsum.photos/seed/alex/100/100" className="w-10 h-10 rounded-full border-2 border-indigo-500" alt="Profile" />
            <div className="overflow-hidden">
              <p className="text-sm font-semibold truncate">Alex Johnson</p>
              <p className="text-xs text-indigo-300">CS Junior</p>
            </div>
          </div>
        </div>
      </aside>

      {/* Mobile Header */}
      <header className="md:hidden flex items-center justify-between p-4 bg-indigo-900 text-white sticky top-0 z-50 shadow-md">
        <div className="flex items-center space-x-2">
          <div className="w-8 h-8 bg-indigo-500 rounded-lg flex items-center justify-center font-bold text-white">EP</div>
          <span className="text-lg font-bold">EduPulse</span>
        </div>
        <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-1">
          {isSidebarOpen ? <X size={28} /> : <Menu size={28} />}
        </button>
      </header>

      {/* Mobile Sidebar (Overlay) */}
      {isSidebarOpen && (
        <div className="md:hidden fixed inset-0 z-40 bg-black/50" onClick={() => setIsSidebarOpen(false)}>
          <div className="w-3/4 max-w-xs h-full bg-white flex flex-col p-6 shadow-2xl" onClick={(e) => e.stopPropagation()}>
            <div className="flex items-center space-x-2 mb-8">
              <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center font-bold text-white">EP</div>
              <span className="text-xl font-bold text-indigo-900">EduPulse</span>
            </div>
            <nav className="flex-1 space-y-2">
              {navItems.map((item) => (
                <Link
                  key={item.name}
                  to={item.path}
                  onClick={() => setIsSidebarOpen(false)}
                  className={`flex items-center space-x-3 p-4 rounded-xl font-medium transition-colors ${
                    location.pathname === item.path ? 'bg-indigo-100 text-indigo-700' : 'text-gray-600'
                  }`}
                >
                  <item.icon size={22} />
                  <span>{item.name}</span>
                </Link>
              ))}
            </nav>
            <div className="pt-6 border-t border-gray-100 mt-auto">
              <div className="flex items-center space-x-3">
                <img src="https://picsum.photos/seed/alex/100/100" className="w-12 h-12 rounded-full border-2 border-indigo-600" alt="Profile" />
                <div>
                  <p className="text-sm font-bold text-gray-900">Alex Johnson</p>
                  <p className="text-xs text-gray-500">2024-8842-EP</p>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Main Content Area */}
      <main className="flex-1 md:ml-64 p-4 md:p-8 min-h-screen">
        {/* Top bar for desktop search/notifications */}
        <div className="hidden md:flex justify-between items-center mb-8">
          <div className="relative w-96">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
            <input 
              type="text" 
              placeholder="Search courses, professors, help..." 
              className="w-full pl-10 pr-4 py-2 bg-white border border-gray-200 rounded-full focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all"
            />
          </div>
          <div className="flex items-center space-x-4">
            <button className="p-2 text-gray-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-full transition-colors relative">
              <Bell size={20} />
              <span className="absolute top-1.5 right-1.5 w-2 h-2 bg-red-500 rounded-full border border-white"></span>
            </button>
            <button className="p-2 text-gray-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-full transition-colors">
              <MessageSquare size={20} />
            </button>
          </div>
        </div>

        {/* Dynamic Page Content */}
        <div className="animate-in fade-in duration-500">
          {children}
        </div>
      </main>
    </div>
  );
};

export default Layout;

import React from 'react';
import { HashRouter, Routes, Route } from 'react-router-dom';
import Layout from './components/Layout';
import Dashboard from './views/Dashboard';
import Academics from './views/Academics';
import Admissions from './views/Admissions';
import Advising from './views/Advising';
import Finances from './views/Finances';

const App: React.FC = () => {
  return (
    <HashRouter>
      <Layout>
        <Routes>
          <Route path="/" element={<Dashboard />} />
          <Route path="/academics" element={<Academics />} />
          <Route path="/admissions" element={<Admissions />} />
          <Route path="/advising" element={<Advising />} />
          <Route path="/finances" element={<Finances />} />
          {/* Fallback */}
          <Route path="*" element={<Dashboard />} />
        </Routes>
      </Layout>
    </HashRouter>
  );
};

export default App;

