                      'bg-white border-gray-200 text-gray-300'
                    }`}>
                      {step.status === 'completed' ? <CheckCircle2 size={16} /> : <Circle size={16} />}
                      {step.status === 'current' && <div className="absolute -inset-1 bg-indigo-600/20 rounded-full animate-ping"></div>}
                    </div>
                    <div className="flex-1 pb-2">
                      <div className="flex justify-between items-center mb-1">
                        <h4 className={`font-bold transition-colors ${step.status === 'upcoming' ? 'text-gray-400' : 'text-gray-800'}`}>
                          {step.name}
                        </h4>
                        <span className="text-[10px] font-bold text-gray-400 flex items-center bg-gray-50 px-2 py-0.5 rounded-lg">
                          <Clock size={10} className="mr-1" />
                          {step.date}
                        </span>
                      </div>
                      <p className="text-xs text-gray-500 max-w-md">
                        {step.status === 'completed' ? 'This milestone was successfully finalized during the review process.' :
                         step.status === 'current' ? 'Actively processing this requirement. Please check your email for updates.' :
                         'This phase will be unlocked once previous requirements are satisfied.'}
                      </p>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>

        {/* Resources */}
        <div className="space-y-6">
          <div className="bg-indigo-50 p-6 rounded-3xl border border-indigo-100">
            <h3 className="font-bold text-indigo-900 mb-4 flex items-center gap-2">
              <FileText size={18} />
              <span>Resources</span>
            </h3>
            <div className="space-y-3">
              {[
                { name: 'Onboarding Checklist', icon: FileText },
                { name: 'Application FAQ', icon: HelpCircle },
                { name: 'Program Curriculum', icon: FileText },
              ].map((doc, i) => (
                <button key={i} className="w-full flex items-center justify-between p-3.5 bg-white rounded-2xl hover:bg-indigo-600 hover:text-white transition-all text-left shadow-sm group">
                  <div className="flex items-center space-x-3">
                    <doc.icon className="text-indigo-400 group-hover:text-indigo-200" size={18} />
                    <span className="text-sm font-bold text-gray-700 group-hover:text-white">{doc.name}</span>
                  </div>
                  <CheckCircle2 size={16} className="text-gray-200 group-hover:text-indigo-400" />
                </button>
              ))}
            </div>
          </div>
          <div className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm">
            <h3 className="font-bold text-gray-800 mb-2">Need Immediate Help?</h3>
            <p className="text-xs text-gray-500 mb-4">Our admission counselors are available for virtual appointments during the peak onboarding season.</p>
            <button className="w-full py-3 bg-indigo-600 text-white rounded-xl font-bold text-sm hover:bg-indigo-700 transition-all">Schedule a Call</button>
          </div>
        </div>
      </div>

      <ContactSection department="admissions" />
    </div>
  );
};

