                    <FileText className="text-indigo-400 group-hover:text-indigo-200" size={18} />
                    <span className="text-sm font-bold text-gray-700 group-hover:text-white">{doc.name}</span>
                  </div>
                  <CheckCircle2 size={16} className="text-gray-200 group-hover:text-indigo-400" />
                </button>
              ))}
            </div>
          </div>
          <div className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm">
            <h3 className="font-bold text-gray-800 mb-2">Need Immediate Help?</h3>
            <p className="text-xs text-gray-500 mb-4">Our admission counselors are available for virtual appointments during the peak onboarding season.</p>
            <button className="w-full py-3 bg-indigo-600 text-white rounded-xl font-bold text-sm hover:bg-indigo-700 transition-all">Schedule a Call</button>
          </div>
        </div>
      </div>

      <ContactSection department="admissions" />
    </div>
  );
};

