import React, { useState, useMemo, useRef, useEffect } from 'react';
import { 
  Library as LibraryIcon, 
  Book, 
  History, 
  AlertTriangle, 
  Clock, 
  ChevronDown, 
  ChevronUp,
  ChevronRight,
  Search,
  BookOpen,
  X,
  Maximize2,
  ExternalLink,
  TableOfContents,
  Sparkles
} from 'lucide-react';
