                        <BookOpen size={16} />
                        Read Now
                      </button>
                    </div>
                    <div className="absolute top-4 right-4 bg-indigo-600 text-white text-[10px] font-black px-3 py-1.5 rounded-full uppercase tracking-widest shadow-lg">
                      {ebook.category}
                    </div>
                    {ebook.termId === 'f24' && (
                      <div className="absolute top-4 left-4 bg-white/90 backdrop-blur-md text-gray-900 text-[10px] font-black px-3 py-1.5 rounded-full uppercase tracking-widest shadow-sm">
                        Fall 2024
                      </div>
                    )}
                  </div>
                  <div className="p-6 flex-1 flex flex-col">
                    <h4 className="font-black text-gray-900 leading-tight mb-1 group-hover:text-indigo-600 transition-colors">{ebook.title}</h4>
